{
  "verses": [
    {
      "n": 3,
      "column": "left",
      "text": "Un Samuels arri bij ap-\ngullees/ pirns tas Deewa Etjes.\nLukturis iſdſehſts tappata KUN-\nGA Namna/ kur tas Deewa\nSchirstis bija."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tad fauze tas KUNGS\nSamuelu/ un tas fazzija: Reds/\nte es efmu/"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Un tas tezzeja pee Eelus/\nun fazzija: Reds/ fche es efmu/\njo tu eſti mann aizinajs; wiꞥſch\nfazzija: Es tew ne esmu aizinajs/\neij atkaſ gulleht/ un tas gahje/\nun apgullahs."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Tad fauze tas KUNGS\nSamuelu atkaſ/ un Samuels\nzeblahs/ un gahje pee Eelus/ un\nfazzija: Rangi/ tu eſti mann ai-\nzinajs/ wiꞥſch fazzija : Es tew\nne esmu aizinajs mans Dehls/\neij atkaſ gulleht."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Bet Samuels weht ne pa-\nsinne to KUNGU/ un ta KUN-\nGA Wahrs tam wehl ne bija\nparahdihts."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Tad fauze tas KUNGS\nSamuelu atkaſ treschan Kahrtan/ un tas zehlchs un gahje pee\nEelus/ un fazzija. Reds/ fche es\nefmu/ tu eſti mann aizinajs/ tad\nnopratte Eelus/ ka tas KUNGS\nto Puift fauze."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un Eelus fazzija uhs Sa-\nmuelu : Eij gulleht/ un kad tu\nfaukts tohpi/ tad talki : Runna\nKUNGS/ jo taws Kalps klaufa. Un Samuels gahje un ap-\ngullahs fauva Weeta."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tad nahze tas KUNGS/\nun pastahweja/ un fauze ka zitt-\nkahrt/ Samuels/ Samuels: Un\nSamuels fazzija : Runna/ jo\ntaws Kalps klausa."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un tas KUNGS fazzija\nus Samuela: Rangi/ es darri\nkahdu Leetu eekſch Israēta/ ka\nwiꞥſam/ kas to dsirdehs/ abbejas\nAufis skannehs."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Tanni Deena pazelschu\nes prett Eelu wiffu/ ko es prett\nwinna Namnu runnajs/ es to\nfahſchu un arri pabeigſchu."
    },
    {
      "n": 13,
      "column": "right",
      "text": "Jo es efmu tam Singu\ndeivis/ ka es Sohgis buhſchu\npahr winna Namnu muhſchtgi\nta Noseeguna deht/ ka wiꞥſch irr\nfinnajs/ ka winna Behrni irr ne-\ntikli turreifschees/ un ne irr wifs\ntohs greſsi usluhkojis."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Un tadeht efmu es tam\nEelus Namnam swehejs/ ka\nEelus Namna Noseegums muh-\nschigi ne taps talihdsnuhts/ nedz\nzaur Uppureem nedz zaur Ehda-\nmo-Uppureem."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un Samuels gullesjahds\nRihaim/ un tad atwehre wiꞥſch\nta KUNGA Namna Durwis/\nbet Samuels bihjajahs scho Pa-\nrahdschann Eelum stahstiht."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tad aizinaja Eelus Sa-\nmuelu/ un fazzija ; Samuels\nmans Dehls. Un tas atbildeja/\nReds/ fche es efmu."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Wiꞥſch fazzija: Kas tas\ntahds Wahrs/ ko Wiꞥſch ustew\nrunnajs? ne apsleppi jelle to\npreekſch mannis/ lai Deciws tew"
    }
  ],
  "confidence": "high",
  "notes": ""
}
